1917 |             conn.setRequestProperty("apikey", key)
1918 |             conn.setRequestProperty("Authorization", "Bearer $key")
1919 |             conn.setRequestProperty("Content-Type", "application/json")
1920 |             conn.doOutput = true
1921 | 
1922 |             val req = JSONObject()
1923 |             req.put("action", "update_command")
1924 |             req.put("deviceId", DeviceManager.getDeviceId(ctx))
1925 |             val payload = JSONObject()
1926 |             payload.put("id", id)
1927 |             payload.put("status", status)
1928 |             if (!errorMsg.isNullOrEmpty()) payload.put("errorMsg", errorMsg)
1929 |             if (resultData != null) payload.put("resultData", resultData)
1930 |             if (!resultFilePath.isNullOrEmpty()) payload.put("resultFilePath", resultFilePath)
1931 |             req.put("payload", payload)
1932 | 
1933 |             val finalJson = req.toString()
1934 |             // SAFETY: Supabase Edge Functions have a limit. If payload is too huge (>2MB), vault it instead of trying.
1935 |             if (finalJson.length > 2 * 1024 * 1024) {
1936 |                 DebugLogger.log("CMD_WARN", "Payload too large for DB update. Moving to Recovery Vault.")
1937 |                 DumpManager.vaultCommandUpdate(id, status, errorMsg, resultData, resultFilePath)
1938 |                 return
1939 |             }
